if (argv[1][0] == '-') {
    printf("Invalid filename\n");
    return 1;
}
for (const unsigned char *p = (const unsigned char *)argv[1]; *p; ++p) {
    if (!(isalnum(*p) || *p == '.' || *p == '/' || *p == '_' || *p == '-')) {
        printf("Invalid filename\n");
        return 1;
    }
